#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

int solve(long long n, vector<vector<long long>> edges, string label) {
    vector<vector<int>> adj(n);
    for (const auto& e : edges) {
        adj[e[0]].push_back(e[1]);
        adj[e[1]].push_back(e[0]);
    }

    int max_len = 1;

    for (int start = 0; start < n; ++start) {
        vector<vector<int>> dp(n, vector<int>(1 << n, -1));
        dp[start][1 << start] = 1;

        for (int mask = 0; mask < (1 << n); ++mask) {
            for (int u = 0; u < n; ++u) {
                if (dp[u][mask] == -1) continue;
                for (int v : adj[u]) {
                    if (mask & (1 << v)) continue;
                    int new_mask = mask | (1 << v);
                    if (dp[v][new_mask] < dp[u][mask] + 1) {
                        dp[v][new_mask] = dp[u][mask] + 1;
                    }
                }
            }
        }

        for (int mask = 0; mask < (1 << n); ++mask) {
            for (int u = 0; u < n; ++u) {
                if (dp[u][mask] == -1) continue;
                unordered_map<char, int> freq;
                for (int i = 0; i < n; ++i) {
                    if (mask & (1 << i)) {
                        freq[label[i]]++;
                    }
                }
                int odd = 0;
                int total = 0;
                for (auto& [c, cnt] : freq) {
                    if (cnt % 2 == 1) {
                        odd++;
                        total += cnt - 1;
                    } else {
                        total += cnt;
                    }
                }
                if (odd > 0) total++;
                if (total > max_len) {
                    max_len = total;
                }
            }
        }
    }

    return max_len;
}

