            int v = (int) edge[1];
            adj.get(u).add(v);
            adj.get(v).add(u);
        }

        int maxLen = 1;

        for (int start = 0; start < numNodes; start++) {
            int[][] dp = new int[numNodes][1 << numNodes];
            for (int[] row : dp) {
                Arrays.fill(row, -1);
            }
            dp[start][1 << start] = 1;

            for (int mask = 0; mask < (1 << numNodes); mask++) {
                for (int u = 0; u < numNodes; u++) {
                    if (dp[u][mask] == -1) continue;
                    for (int v : adj.get(u)) {
                        if ((mask & (1 << v)) != 0) continue;
                        int newMask = mask | (1 << v);
                        if (dp[v][newMask] < dp[u][mask] + 1) {
                            dp[v][newMask] = dp[u][mask] + 1;
                        }
                    }
                }
            }

            for (int mask = 0; mask < (1 << numNodes); mask++) {
                for (int u = 0; u < numNodes; u++) {
                    if (dp[u][mask] == -1) continue;
                    Map<Character, Integer> freq = new HashMap<>();
                    for (int i = 0; i < numNodes; i++) {
                        if ((mask & (1 << i)) != 0) {
